const HOST = 'n8n.srv1076230.hstgr.cloud';
const WF_PAGEVIEW = 'rkvyZWct7TVyfu4S';
const WF_LEAD = 'yhPDszmBJ4dASAeV';
const PERIOD_DAYS = $input.first().json.periodDays || 7;

async function fetchJson(path) {
  return await this.helpers.httpRequest({
    url: 'https://' + HOST + path, method: 'GET',
    headers: { 'X-N8N-API-KEY': API_KEY }, json: true
  });
}
async function fetchExecutions(id, limit) {
  return (await fetchJson('/api/v1/executions?workflowId=' + id + '&limit=' + limit + '&includeData=true')).data || [];
}
async function fetchWorkflow(id) { return await fetchJson('/api/v1/workflows/' + id); }

function analyze(executions, since) {
  let total = 0, success = 0, errors = 0;
  let withFbc = 0, withFbp = 0, withEmail = 0, withPhone = 0;
  let metaReceived = 0;
  const errorList = [];

  for (const ex of executions) {
    const t = new Date(ex.startedAt).getTime();
    if (t < since) continue;
    total++;
    if (ex.status === 'success') success++; else errors++;

    const rd = ex.data && ex.data.resultData && ex.data.resultData.runData;
    if (!rd) continue;

    const pk = Object.keys(rd).find(k => k.includes('Przygotuj'));
    if (pk) {
      const out = rd[pk][0] && rd[pk][0].data && rd[pk][0].data.main && rd[pk][0].data.main[0] && rd[pk][0].data.main[0][0] && rd[pk][0].data.main[0][0].json;
      const ud = out && out.capiData && out.capiData.data && out.capiData.data[0] && out.capiData.data[0].user_data;
      if (ud) {
        if (ud.fbc) withFbc++;
        if (ud.fbp) withFbp++;
        if (ud.em) withEmail++;
        if (ud.ph) withPhone++;
      }
    }
    const ck = Object.keys(rd).find(k => k.includes('CAPI'));
    if (ck) {
      const r = rd[ck][0] && rd[ck][0].data && rd[ck][0].data.main && rd[ck][0].data.main[0] && rd[ck][0].data.main[0][0] && rd[ck][0].data.main[0][0].json;
      if (r && typeof r.events_received === 'number') metaReceived += r.events_received;
      if (rd[ck][0] && rd[ck][0].error) errorList.push({ time: new Date(ex.startedAt).toISOString(), msg: rd[ck][0].error.message });
    }
  }

  const pct = (a, b) => b > 0 ? Math.round(100 * a / b) : 0;

  // Quality score = weighted avg parametrow match
  // Dla Lead najwazniejsze: em, ph, fbc, fbp (kazdy po 25%)
  // Dla PageView: fbp 40%, fbc 40%, external_id 20% (external_id zawsze jest wiec +20)
  const qualityLead = total > 0 ? Math.round((25*withEmail + 25*withPhone + 25*withFbc + 25*withFbp) / total) : 0;
  const qualityPv = total > 0 ? Math.round((40*withFbc + 40*withFbp + 20*total) / total) : 0;

  return {
    total, success, errors,
    successRate: pct(success, total),
    withFbc, withFbp, withEmail, withPhone,
    fbcRate: pct(withFbc, total),
    fbpRate: pct(withFbp, total),
    emailRate: pct(withEmail, total),
    phoneRate: pct(withPhone, total),
    metaReceived,
    qualityLead, qualityPv,
    errorList: errorList.slice(0, 10)
  };
}

const now = Date.now();
const sinceCurrent = now - PERIOD_DAYS * 24 * 60 * 60 * 1000;
const sincePrev = now - 2 * PERIOD_DAYS * 24 * 60 * 60 * 1000;

const pvWf = await fetchWorkflow(WF_PAGEVIEW);
const leadWf = await fetchWorkflow(WF_LEAD);

const pvExecs = await fetchExecutions(WF_PAGEVIEW, 250);
const leadExecs = await fetchExecutions(WF_LEAD, 100);

const pvCurrent = analyze.call(this, pvExecs, sinceCurrent);
const pvAll = analyze.call(this, pvExecs, sincePrev);
const pvPrev = {
  total: pvAll.total - pvCurrent.total,
  success: pvAll.success - pvCurrent.success,
  withFbc: pvAll.withFbc - pvCurrent.withFbc,
  fbcRate: (pvAll.total - pvCurrent.total) > 0 ? Math.round(100*(pvAll.withFbc - pvCurrent.withFbc)/(pvAll.total - pvCurrent.total)) : 0
};

const leadCurrent = analyze.call(this, leadExecs, sinceCurrent);
const leadAll = analyze.call(this, leadExecs, sincePrev);
const leadPrev = {
  total: leadAll.total - leadCurrent.total,
  success: leadAll.success - leadCurrent.success,
  withFbc: leadAll.withFbc - leadCurrent.withFbc,
  fbcRate: (leadAll.total - leadCurrent.total) > 0 ? Math.round(100*(leadAll.withFbc - leadCurrent.withFbc)/(leadAll.total - leadCurrent.total)) : 0
};

// ===== WARTOSC DODANA CAPI =====
// "Odzyskane eventy" = te z fbc (ruch z reklam Meta ktorego przegladarkowe cookies 3rd-party juz nie dopasuja)
const recoveredPageView = pvCurrent.withFbc;
const recoveredLead = leadCurrent.withFbc;

// Szacunkowy wzrost raportowanych konwersji wg deklaracji Mety:
// - PageView z fbc: median +100% raportowanych konwersji
// - Lead z em+ph+fbc: median +150% (pelne dopasowanie)
const estimatedExtraConversions = recoveredLead; // 1:1 approximation (konserwatywne)

// Alerts
const alerts = [];
if (!pvWf.active) alerts.push('Workflow PageView CAPI NIEAKTYWNY');
if (!leadWf.active) alerts.push('Workflow Lead CAPI NIEAKTYWNY');
if (pvCurrent.total === 0) alerts.push('ZERO wykonan PageView w ostatnich ' + PERIOD_DAYS + ' dniach!');
if (pvPrev.total > 10 && pvCurrent.total < pvPrev.total * 0.5) alerts.push('Spadek PageView o ' + Math.round(100 - 100*pvCurrent.total/pvPrev.total) + '% vs poprzedni tydzien');
if (pvCurrent.errors > 0) alerts.push(pvCurrent.errors + ' bledow PageView');
if (leadCurrent.errors > 0) alerts.push(leadCurrent.errors + ' bledow Lead');

const deltaPct = (a, b) => b > 0 ? Math.round((a - b) / b * 100) : 0;

return [{
  json: {
    periodDays: PERIOD_DAYS,
    generatedAt: new Date().toLocaleString('pl-PL'),
    pageview: {
      active: pvWf.active, current: pvCurrent, prev: pvPrev,
      deltaPct: deltaPct(pvCurrent.total, pvPrev.total)
    },
    lead: {
      active: leadWf.active, current: leadCurrent, prev: leadPrev,
      deltaPct: deltaPct(leadCurrent.total, leadPrev.total)
    },
    value: {
      recoveredPageView,
      recoveredLead,
      estimatedExtraConversions,
      totalCapiEvents: pvCurrent.total + leadCurrent.total,
      leadWithFullMatch: leadCurrent.withEmail > 0 ? Math.min(leadCurrent.withEmail, leadCurrent.withPhone) : 0
    },
    alerts,
    hasAlerts: alerts.length > 0
  }
}];

